@namespace Lumeo

@{
    var context = new NavigationMenuContext(_activeItemId, EventCallback.Factory.Create<string?>(this, SetActiveItemId));
}

<nav class="@CssClass" @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</nav>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string? _activeItemId;

    private string CssClass => $"relative z-10 flex max-w-max flex-1 items-center justify-center {Class}".Trim();

    private Task SetActiveItemId(string? value)
    {
        _activeItemId = value;
        StateHasChanged();
        return Task.CompletedTask;
    }

    public record NavigationMenuContext(string? ActiveItemId, EventCallback<string?> SetActiveItemId);
}

@namespace Lumeo
@implements IAsyncDisposable

@if (Context.ActiveItemId == ItemContext.ItemId)
{
    <div id="@_contentId" class="@CssClass" @onkeydown="HandleKeyDown" tabindex="-1" @attributes="AdditionalAttributes">
        <div class="@InnerCssClass">
            @ChildContent
        </div>
    </div>
}

@inject ComponentInteropService Interop

@code {
    [CascadingParameter] public NavigationMenu.NavigationMenuContext Context { get; set; } = default!;
    [CascadingParameter] public NavigationMenuItem.NavigationMenuItemContext ItemContext { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _contentId = $"nav-content-{Guid.NewGuid():N}";
    private bool _registered;

    private string CssClass => $"fixed z-50 animate-fade-in {Class}".Trim();

    private string InnerCssClass => "mt-1.5 min-w-[12rem] overflow-hidden rounded-md border border-border bg-popover p-4 text-popover-foreground shadow-lg";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (Context.ActiveItemId == ItemContext.ItemId && !_registered)
        {
            await Interop.PositionFixed(_contentId, ItemContext.TriggerId, "start");
            await Interop.RegisterClickOutside(_contentId, ItemContext.TriggerId, async () =>
            {
                await Context.SetActiveItemId.InvokeAsync(null);
                await InvokeAsync(StateHasChanged);
            });
            _registered = true;
        }
        else if (Context.ActiveItemId != ItemContext.ItemId && _registered)
        {
            await Cleanup();
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape")
        {
            await Context.SetActiveItemId.InvokeAsync(null);
        }
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(_contentId); } catch (JSDisconnectedException) { }
        try { await Interop.UnregisterClickOutside(_contentId); } catch (JSDisconnectedException) { }
        _registered = false;
    }

    public async ValueTask DisposeAsync()
    {
        if (_registered) await Cleanup();
    }
}

@namespace Lumeo

<button type="button" class="@CssClass" @onclick="Toggle" aria-label="Toggle navigation" @attributes="AdditionalAttributes">
